mapper.update:
update f_review
set
fr_subject 	= #{fr_subject},
fr_star 	= #{fr_star},
fr_content 	= #{fr_content}



			AND fr_idx = #{fr_idx}


			AND	id = #{id}
			AND f_code = #{f_code}

mapper.select:
select F_REVIEW.id as id, F_REVIEW.f_code as f_code, fr_subject, fr_star, fr_createdDate, fr_content, FURNITURE.f_name as f_name, fr_idx, c_id, cart.F_PRICE as payment, cart.F_POINT as usedPoint, cart.F_COUNT as qty, F_REVIEW.C_CODE as c_code from f_review join FURNITURE ON F_REVIEW.F_CODE = FURNITURE.F_CODE left outer join CART on F_REVIEW.C_CODE = CART.C_CODE
AND F_REVIEW.id = #{id}
AND fr_idx = #{fr_idx}
AND c_id = #{c_id}
AND F_REVIEW.f_code = #{f_code}

mapper.delete:
delete from f_review
where
	id = #{id}
	and f_code = #{f_code}
	and c_code = #{c_code}
